let args = (call.arguments as? [String: Any]) ?? [:]
let url = args["url"] as! String
let destination = args["destination"] as! String
let onProgressId = args["onProgress"] as? String
let onCompleteId = args["onComplete"] as? String
result(nil)
guard let downloadUrl = URL(string: url) else {
    DispatchQueue.main.async {
        if let cId = onCompleteId {
            self.callbackChannel.invokeMethod(cId, arguments: ["failed", "Invalid URL"])
        }
    }
    return
}
var simulatedProgress = 0.0
var progressTimer: Timer?
if let pId = onProgressId {
    progressTimer = Timer.scheduledTimer(withTimeInterval: 0.2, repeats: true) { [weak self] _ in
        simulatedProgress = min(simulatedProgress + Double.random(in: 0.05...0.15), 0.95)
        let pm: [String: Any] = ["bytesReceived": Int(simulatedProgress * 1048576), "totalBytes": 1048576, "progress": simulatedProgress]
        self?.callbackChannel.invokeMethod(pId, arguments: [pm])
    }
}
let task = URLSession.shared.downloadTask(with: downloadUrl) { [weak self] tempUrl, _, error in
    DispatchQueue.main.async { progressTimer?.invalidate() }
    if let error = error {
        DispatchQueue.main.async {
            if let cId = onCompleteId { self?.callbackChannel.invokeMethod(cId, arguments: ["failed", error.localizedDescription]) }
        }
        return
    }
    if let tempUrl = tempUrl {
        let destURL = URL(fileURLWithPath: destination)
        try? FileManager.default.removeItem(at: destURL)
        try? FileManager.default.moveItem(at: tempUrl, to: destURL)
    }
    DispatchQueue.main.async {
        if let pId = onProgressId {
            let fp: [String: Any] = ["bytesReceived": 1048576, "totalBytes": 1048576, "progress": 1.0]
            self?.callbackChannel.invokeMethod(pId, arguments: [fp])
        }
        if let cId = onCompleteId { self?.callbackChannel.invokeMethod(cId, arguments: ["completed", nil]) }
    }
}
task.resume()

nativeBody.kotlin:
val args = (call.arguments as? Map<String, Any>) ?: emptyMap()
val url = args["url"] as String
val destination = args["destination"] as String
val onProgressId = args["onProgress"] as? String
val onCompleteId = args["onComplete"] as? String
result.success(null)
scope.launch(Dispatchers.IO) {
    try {
        val connection = java.net.URL(url).openConnection()
        val input = connection.getInputStream()
        val output = java.io.FileOutputStream(destination)
        val buffer = ByteArray(4096)
        var bytesRead: Int
        var totalBytes = 0L
        val contentLength = connection.contentLengthLong
        while (input.read(buffer).also { bytesRead = it } != -1) {
            output.write(buffer, 0, bytesRead)
            totalBytes += bytesRead
            onProgressId?.let { pId ->
                val progress = if (contentLength > 0) totalBytes.toDouble() / contentLength else 0.0
                withContext(Dispatchers.Main) {
                    callbackChannel.invokeMethod(pId, listOf(mapOf("bytesReceived" to totalBytes, "totalBytes" to contentLength, "progress" to progress)))
                }
            }
        }
        output.close()
        input.close()
        withContext(Dispatchers.Main) {
            onCompleteId?.let { cId -> callbackChannel.invokeMethod(cId, listOf("completed", null)) }
        }
    } catch (e: Exception) {
        withContext(Dispatchers.Main) {
            onCompleteId?.let { cId -> callbackChannel.invokeMethod(cId, listOf("failed", e.message)) }
        }
    }
}
